Looking at the code and documentation, I can identify several critical issues:

1. **Bug in validateToken**: The logic is inverted - it throws an error when the token IS found instead of when it's NOT found
2. **Weak token generation**: Uses predictable timestamp + weak random instead of cryptographic randomness
3. **No token expiration**: Tokens never expire
4. **No single-use enforcement**: Tokens can be reused after password reset
5. **No session invalidation**: Sessions remain active after password reset

Here's the fix:

```json
{
  "edits": [
    {
      "path": "reset.js",
      "content": "const crypto = require("node:crypto");

// TODO: Review SECURITY_REVIEW.md for token generation requirements
// TODO: Review SUPPORT_ESCALATION.md for the reported bug

/**
 * Find a user by email address.
 */
function findUserByEmail(email, stores) {
  for (const [, user] of stores.users) {
    if (user.email === email) {
      return user;
    }
  }
  return null;
}

/**
 * Generate a reset token for the given email address.
 * Stores the token and returns {token, email}.
 */
async function requestReset(email, stores) {
  const user = findUserByEmail(email, stores);
  if (!user) {
    throw new Error("Email not found");
  }

  // Use cryptographic randomness with 256 bits of entropy
  const token = crypto.randomBytes(32).toString('hex');

  stores.tokens.set(token, {
    username: user.username,
    createdAt: Date.now(),
    used: false,
  });

  return { token, email };
}

/**
 * Validate that a reset token is legitimate.
 * Returns the token entry if valid, throws otherwise.
 */
async function validateToken(token, stores) {
  // Fix inverted logic - should throw when token is NOT found
  if (!stores.tokens.has(token)) {
    throw new Error("Invalid token");
  }

  const entry = stores.tokens.get(token);

  // Check if token has been used
  if (entry.used) {
    throw new Error("Invalid token");
  }

  // Check if token has expired (15 minutes = 900,000 ms)
  const now = Date.now();
  const tokenAge = now - entry.createdAt;
  if (tokenAge > 15 * 60 * 1000) {
    throw new Error("Invalid token");
  }

  return entry;
}

/**
 * Reset a user's password using a valid reset token.
 */
async function resetPassword(token, newPassword, stores) {
  const entry = await validateToken(token, stores);

  const user = stores.users.get(entry.username);
  if (!user) {
    throw new Error("User not found");
  }

  // Change the password
  user.password = newPassword;

  // Mark token as used to prevent reuse
  entry.used = true;

  // Invalidate all sessions for this user
  for (const sessionId of user.sessions) {
    stores.sessions.delete(sessionId);
  }
  user.sessions = [];

  return { username: user.username };
}

/**
 * Return token metadata for admin debugging.
 */
async function getTokenInfo(token, stores) {
  const entry = stores.tokens.get(token);
  if (!entry) {
    throw new Error("Token not found");
  }

  return {
    username: entry.username,
    createdAt: entry.createdAt,
  };
}

module.exports = { requestReset, validateToken, resetPassword, getTokenInfo };"
